  def validateColumnName(column: String, tables: List[String]): ValidationResult = {
    val trimmed = column.trim
    // Allow aggregate expressions like COUNT(*), SUM(amount), etc.
    val aggPattern = "(?i)^(COUNT|SUM|AVG|MIN|MAX|ROUND|COALESCE|CAST|UPPER|LOWER|YEAR|MONTH|DAY|DATE|TRIM|DISTINCT)\\s*\\((.+)\\)$".r
    val aliasPattern = "^(.+)\\s+(?i)AS\\s+(\\w+)$".r
    val starPattern = "^\\*$".r

    trimmed match {
      case starPattern() => Valid
      case aliasPattern(expr, alias) =>
        if (!alias.matches("^[a-zA-Z_][a-zA-Z0-9_]*$"))
          Invalid(s"Invalid alias: '$alias'")
        else
          validateColumnName(expr.trim, tables)
      case aggPattern(func, inner) =>
        val normalizedFunc = func.toUpperCase
        if (!allowedFunctions.contains(normalizedFunc))
          Invalid(s"Function '$func' is not allowed.")
        else if (inner.trim == "*")
          Valid
        else
          validateColumnName(inner.trim, tables)
      case _ =>
        // Handle table.column format
        val parts = trimmed.split("\\.", 2)
        val colName = if (parts.length == 2) {
          val tbl = parts(0).trim.toLowerCase
          if (!allowedTables.contains(tbl))
            return Invalid(s"Table prefix '$tbl' is not in the allowlist.")
          parts(1).trim.toLowerCase
        } else {
          trimmed.toLowerCase
        }

        val normalizedTables = tables.map(_.trim.toLowerCase)
        val allAllowedCols = normalizedTables.flatMap(t => allowedColumns.getOrElse(t, Set.empty)).toSet

        if (allAllowedCols.contains(colName)) Valid
        else Invalid(s"Column '$colName' is not in the allowlist for tables: ${normalizedTables.mkString(", ")}.")
    }
  }

