  def buildParameterizedSQL(query: AnalyticsQuery): (String, Map[String, Any]) = {
    val params = scala.collection.mutable.Map[String, Any]()
    var paramIndex = 0

    def nextParamName(): String = {
      paramIndex += 1
      s"param_$paramIndex"
    }

    val sb = new StringBuilder()

    // SELECT
    sb.append("SELECT ")
    sb.append(query.selectColumns.mkString(", "))

    // FROM
    sb.append(" FROM ")
    sb.append(query.tables.head)

    // JOINs
    for (join <- query.joins) {
      sb.append(s" ${join.joinType} ${join.table} ON ${join.leftColumn} = ${join.rightColumn}")
    }

    // WHERE with parameterized values
    if (query.filters.nonEmpty) {
      sb.append(" WHERE ")
      val filterClauses = query.filters.map { filter =>
        val paramName = nextParamName()
        val sanitizedValue = sanitizeParameterValue(filter.value)
        params(paramName) = sanitizedValue

        filter.operator.toUpperCase match {
          case "IN" =>
            sanitizedValue match {
              case list: List[_] =>
                val inParams = list.map { v =>
                  val pn = nextParamName()
                  params(pn) = v
                  s"{$pn}"
                }
                s"${filter.column} IN (${inParams.mkString(", ")})"
              case _ =>
                s"${filter.column} ${filter.operator} {$paramName}"
            }
          case "BETWEEN" =>
            sanitizedValue match {
              case (low, high) =>
                val pnLow = nextParamName()
                val pnHigh = nextParamName()
                params(pnLow) = low
                params(pnHigh) = high
                s"${filter.column} BETWEEN {$pnLow} AND {$pnHigh}"
              case _ =>
                s"${filter.column} ${filter.operator} {$paramName}"
            }
          case "IS NULL" | "IS NOT NULL" =>
            params.remove(paramName)
            s"${filter.column} ${filter.operator}"
          case "LIKE" =>
            s"${filter.column} LIKE {$paramName}"
          case _ =>
            s"${filter.column} ${filter.operator} {$paramName}"
        }
      }
      sb.append(filterClauses.mkString(" AND "))
    }

    // GROUP BY
    if (query.groupByColumns.nonEmpty) {
      sb.append(" GROUP BY ")
      sb.append(query.groupByColumns.mkString(", "))
    }

    // HAVING with parameterized values
    if (query.havingConditions.nonEmpty) {
      sb.append(" HAVING ")
      val havingClauses = query.havingConditions.map { filter =>
        val paramName = nextParamName()
        params(paramName) = sanitizeParameterValue(filter.value)
        s"${filter.column} ${filter.operator} {$paramName}"
      }
      sb.append(havingClauses.mkString(" AND "))
    }

    // ORDER BY
    if (query.orderByColumns.nonEmpty) {
      sb.append(" ORDER BY ")
      sb.append(query.orderByColumns.map(o => s"${o.column} ${o.direction}").mkString(", "))
    }

    // LIMIT
    query.limit.foreach { l =>
      val paramName = nextParamName()
      params(paramName) = l
      sb.append(s" LIMIT {$paramName}")
    }

    // OFFSET
    query.offset.foreach { o =>
      val paramName = nextParamName()
      params(paramName) = o
      sb.append(s" OFFSET {$paramName}")
    }

    (sb.toString(), params.toMap)
  }

  def executeParameterizedQuery(sql: String, params: Map[String, Any]): DataFrame = {
    // Use Spark's built-in parameterized query support (Spark 3.4+)
    // This safely handles parameter binding without string interpolation
    import scala.collection.JavaConverters._

    val sparkParams: java.util.Map[String, String] = params.map {
      case (k, v: String) => k -> s"'${escapeStringLiteral(v)}'"
      case (k, v: Int) => k -> v.toString
      case (k, v: Long) => k -> v.toString
      case (k, v: Double) => k -> v.toString
      case (k, v: Float) => k -> v.toString
      case (k, v: Boolean) => k -> v.toString
      case (k, v: BigDecimal) => k -> v.toString
      case (k, v) => k -> v.toString
    }.asJava

    // Replace {paramName} with properly typed literals for Spark SQL
    var resolvedSql = sql
    params.foreach {
      case (name, v: String) =>
        resolvedSql = resolvedSql.replace(s"{$name}", s"'${escapeStringLiteral(v)}'")
      case (name, v) =>
        resolvedSql = resolvedSql.replace(s"{$name}", v.toString)
    }

    spark.sql(resolvedSql)
  }

  def escapeStringLiteral(input: String): String = {
    input
      .replace("\\", "\\\\")
      .replace("'", "\\'")
      .replace("\n", "\\n")
      .replace("\r", "\\r")
      .replace("\t", "\\t")
      .replace("\u0000", "")
  }

  // API endpoint handler
  def handleQueryRequest(request: QueryRequest): QueryResponse = {
    // Check raw input for injection patterns first
    val rawCheck = checkForDeniedPatterns(request.toString)
    rawCheck match {
      case Invalid(reason) =>
        return QueryResponse(success = false, error = Some(reason), data = None)
      case Valid =>
    }

    val analyticsQuery = parseQueryRequest(request)

    buildAndExecuteQuery(analyticsQuery) match {
      case Right(df) =>
        val results = df.toJSON.collect().toList
        QueryResponse(success = true, error = None, data = Some(results))
      case Left(errorMsg) =>
        QueryResponse(success = false, error = Some(errorMsg), data = None)
    }
  }

