  def parseQueryRequest(request: QueryRequest): AnalyticsQuery = {
    AnalyticsQuery(
      selectColumns = request.select,
      tables = request.from,
      joins = request.joins.getOrElse(List.empty).map(j =>
        JoinClause(j.joinType, j.table, j.leftColumn, j.rightColumn)
      ),
      filters = request.where.getOrElse(List.empty).map(f =>
        FilterCondition(f.column, f.operator, f.value)
      ),
      groupByColumns = request.groupBy.getOrElse(List.empty),
      orderByColumns = request.orderBy.getOrElse(List.empty).map(o =>
        OrderByClause(o.column, o.direction)
      ),
      havingConditions = request.having.getOrElse(List.empty).map(f =>
        FilterCondition(f.column, f.operator, f.value)
      ),
      limit = request.limit,
      offset = request.offset
    )
  }

